import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface DailyChecklist {
  dawnPrayer: boolean;
  morningPrayer: boolean;
  noonPrayer: boolean;
  afternoonPrayer: boolean;
  nightPrayer: boolean;
  worship: boolean;
  exercise: boolean;
  recitation: boolean;
  cleaning: boolean;
  organization: boolean;
  recycling: boolean;
  hygiene: boolean;
  doorLightCheck: boolean;
  environmentCheck: boolean;
  slowChewing: boolean;
  bedsidePrep: boolean;
}

export interface ReadingLog {
  id: string;
  bookTitle: string;
  pages: number;
  highlight: string;
  createdAt: string;
}

export interface BibleLog {
  id: string;
  book: string;
  chapter: number;
  chapterCount: number;
  createdAt: string;
}

export interface DailyData {
  date: string; // YYYY-MM-DD
  checklist: DailyChecklist;
  readingLogs: ReadingLog[];
  bibleLogs: BibleLog[];
}

export type ViewType = 'today' | 'journals' | 'video' | 'stats';

import { DailyData, DailyChecklist } from '../types';

const STORAGE_KEY = 'new_life_app_data';

export const getDefaultChecklist = (): DailyChecklist => ({
  dawnPrayer: false,
  morningPrayer: false,
  noonPrayer: false,
  afternoonPrayer: false,
  nightPrayer: false,
  worship: false,
  exercise: false,
  recitation: false,
  cleaning: false,
  organization: false,
  recycling: false,
  hygiene: false,
  doorLightCheck: false,
  environmentCheck: false,
  slowChewing: false,
  bedsidePrep: false,
});

export const getDailyData = (date: string): DailyData => {
  const allData = getAllData();
  return allData[date] || {
    date,
    checklist: getDefaultChecklist(),
    readingLogs: [],
    bibleLogs: [],
  };
};

export const saveDailyData = (data: DailyData) => {
  const allData = getAllData();
  allData[data.date] = data;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(allData));
};

export const getAllData = (): Record<string, DailyData> => {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw ? JSON.parse(raw) : {};
};

import React from 'react';
import { CheckSquare, Book, Play, BarChart2 } from 'lucide-react';
import { ViewType } from '../types';

interface NavigationProps {
  currentView: ViewType;
  setView: (view: ViewType) => void;
}

const Navigation: React.FC<NavigationProps> = ({ currentView, setView }) => {
  const navItems = [
    { id: 'today', label: '체크리스트', icon: <CheckSquare /> },
    { id: 'journals', label: '기록장', icon: <Book /> },
    { id: 'video', label: '영상묵상', icon: <Play /> },
    { id: 'stats', label: '통계', icon: <BarChart2 /> },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 px-4 py-2 flex justify-around items-center z-50">
      {navItems.map((item) => (
        <button
          key={item.id}
          onClick={() => setView(item.id as ViewType)}
          className={`flex flex-col items-center gap-1 p-2 transition-colors ${
            currentView === item.id ? 'text-emerald-600' : 'text-slate-400'
          }`}
        >
          {React.cloneElement(item.icon as React.ReactElement, { size: 24 })}
          <span className="text-[10px] font-medium">{item.label}</span>
        </button>
      ))}
