export default Navigation;

import React from 'react';
import { DailyData, DailyChecklist as IChecklist } from '../types';
import { CHECKLIST_ITEMS } from '../constants';
import { Check } from 'lucide-react';

interface DailyChecklistProps {
  data: DailyData;
  onUpdate: (data: DailyData) => void;
}

const DailyChecklist: React.FC<DailyChecklistProps> = ({ data, onUpdate }) => {
  const toggleItem = (itemId: keyof IChecklist) => {
    const newData: DailyData = {
      ...data,
      checklist: {
        ...data.checklist,
        [itemId]: !data.checklist[itemId],
      },
    };
    onUpdate(newData);
  };

  const completedCount = Object.values(data.checklist).filter(Boolean).length;
  const totalCount = CHECKLIST_ITEMS.length;
  const progressPercent = Math.round((completedCount / totalCount) * 100);

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
        <div className="flex justify-between items-end mb-4">
          <div>
            <h2 className="text-xl font-bold text-slate-800">오늘의 생활 체크</h2>
            <p className="text-slate-500 text-sm">성실함이 기적을 만듭니다.</p>
          </div>
          <div className="text-right">
            <span className="text-2xl font-bold text-emerald-600">{progressPercent}%</span>
            <p className="text-xs text-slate-400">{completedCount} / {totalCount}</p>
          </div>
        </div>
        <div className="w-full bg-slate-100 h-2 rounded-full overflow-hidden">
          <div 
            className="bg-emerald-500 h-full transition-all duration-500" 
            style={{ width: `${progressPercent}%` }}
          />
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {CHECKLIST_ITEMS.map((item) => (
          <button
            key={item.id}
            onClick={() => toggleItem(item.id as keyof IChecklist)}
            className={`flex items-center gap-3 p-4 rounded-2xl text-left border transition-all duration-200 ${
              data.checklist[item.id as keyof IChecklist]
                ? 'bg-emerald-50 border-emerald-200 shadow-sm'
                : 'bg-white border-slate-100'
            }`}
          >
            <div className={`p-2 rounded-xl ${
              data.checklist[item.id as keyof IChecklist] ? 'bg-white' : 'bg-slate-50'
            }`}>
              {item.icon}
            </div>
            <div className="flex-1 min-w-0">
              <p className={`text-sm font-semibold truncate ${
                data.checklist[item.id as keyof IChecklist] ? 'text-emerald-900' : 'text-slate-700'
              }`}>
                {item.label}
              </p>
            </div>
            {data.checklist[item.id as keyof IChecklist] && (
              <Check className="w-4 h-4 text-emerald-600 flex-shrink-0" />
            )}
          </button>
        ))}
      </div>
    </div>
  );
};

export default DailyChecklist;

import React, { useState } from 'react';
import { DailyData, ReadingLog, BibleLog } from '../types';
import { BIBLE_BOOKS } from '../constants';
import { Plus, Trash2, BookOpen, Scroll } from 'lucide-react';

interface JournalSectionProps {
  data: DailyData;
  onUpdate: (data: DailyData) => void;
}

const JournalSection: React.FC<JournalSectionProps> = ({ data, onUpdate }) => {
  const [readingForm, setReadingForm] = useState({ bookTitle: '', pages: 0, highlight: '' });
  const [bibleForm, setBibleForm] = useState({ book: '창세기', chapter: 1, chapterCount: 1 });

  const addReadingLog = () => {
    if (!readingForm.bookTitle) return;
    const newLog: ReadingLog = {
      id: Date.now().toString(),
      ...readingForm,
      createdAt: new Date().toISOString(),
    };
    onUpdate({ ...data, readingLogs: [newLog, ...data.readingLogs] });
    setReadingForm({ bookTitle: '', pages: 0, highlight: '' });
  };

  const addBibleLog = () => {
    const newLog: BibleLog = {
      id: Date.now().toString(),
      ...bibleForm,
      createdAt: new Date().toISOString(),
    };
    onUpdate({ ...data, bibleLogs: [newLog, ...data.bibleLogs] });
  };

  const removeLog = (type: 'reading' | 'bible', id: string) => {
    if (type === 'reading') {
      onUpdate({ ...data, readingLogs: data.readingLogs.filter(l => l.id !== id) });
    } else {
      onUpdate({ ...data, bibleLogs: data.bibleLogs.filter(l => l.id !== id) });
    }
  };

  return (
    <div className="space-y-8 pb-20">
      {/* Bible Section */}
      <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
        <div className="flex items-center gap-2 mb-6">
          <Scroll className="text-purple-500" />
          <h2 className="text-xl font-bold text-slate-800">성경 읽기 일지</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6 p-4 bg-slate-50 rounded-xl">
          <div>
            <label className="block text-xs font-semibold text-slate-500 mb-1">성경 책</label>
            <select 
              value={bibleForm.book}
              onChange={e => setBibleForm({...bibleForm, book: e.target.value})}
              className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-purple-200 outline-none"
            >
              {BIBLE_BOOKS.map(b => <option key={b} value={b}>{b}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-500 mb-1">시작 장</label>
            <input 
              type="number"
              value={bibleForm.chapter}
              onChange={e => setBibleForm({...bibleForm, chapter: parseInt(e.target.value) || 0})}
              className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-purple-200 outline-none"
            />
          </div>
          <div className="flex gap-2">
            <div className="flex-1">
              <label className="block text-xs font-semibold text-slate-500 mb-1">읽은 장 수</label>
              <input 
                type="number"
                value={bibleForm.chapterCount}
                onChange={e => setBibleForm({...bibleForm, chapterCount: parseInt(e.target.value) || 0})}
                className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-purple-200 outline-none"
              />
            </div>
            <button 
              onClick={addBibleLog}
              className="mt-5 bg-purple-600 text-white p-2 rounded-lg hover:bg-purple-700 transition-colors self-start"
            >
              <Plus />
            </button>
          </div>
        </div>

        <div className="space-y-3">
          {data.bibleLogs.map(log => (
            <div key={log.id} className="flex justify-between items-center p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
              <div className="flex items-center gap-3">
                <div className="w-1.5 h-1.5 rounded-full bg-purple-400"></div>
                <span className="font-semibold text-slate-800">{log.book} {log.chapter}장</span>
                <span className="text-xs text-slate-400">({log.chapterCount}장 읽음)</span>
              </div>
              <button onClick={() => removeLog('bible', log.id)} className="text-slate-300 hover:text-red-500 transition-colors">
                <Trash2 size={16} />
              </button>
            </div>
          ))}
          {data.bibleLogs.length === 0 && <p className="text-center text-slate-400 text-sm py-4">오늘의 말씀 기록이 없습니다.</p>}
        </div>
      </section>

      {/* Reading Section */}
      <section className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
        <div className="flex items-center gap-2 mb-6">
          <BookOpen className="text-emerald-500" />
          <h2 className="text-xl font-bold text-slate-800">독서 일지</h2>
        </div>

        <div className="space-y-4 mb-6 p-4 bg-slate-50 rounded-xl">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1">책 제목</label>
              <input 
                placeholder="책 제목을 입력하세요"
                value={readingForm.bookTitle}
                onChange={e => setReadingForm({...readingForm, bookTitle: e.target.value})}
                className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-200 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-slate-500 mb-1">읽은 페이지 수</label>
              <input 
                type="number"
                value={readingForm.pages}
                onChange={e => setReadingForm({...readingForm, pages: parseInt(e.target.value) || 0})}
                className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-200 outline-none"
              />
            </div>
          </div>
          <div>
            <label className="block text-xs font-semibold text-slate-500 mb-1">인상 깊은 글</label>
            <textarea 
              rows={3}
              placeholder="기억하고 싶은 내용을 적어주세요"
              value={readingForm.highlight}
              onChange={e => setReadingForm({...readingForm, highlight: e.target.value})}
              className="w-full bg-white border border-slate-200 rounded-lg p-2 text-sm focus:ring-2 focus:ring-emerald-200 outline-none resize-none"
            />
          </div>
          <button 
            onClick={addReadingLog}
            className="w-full bg-emerald-600 text-white font-bold py-2 rounded-lg hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2"
          >
            <Plus size={20} /> 기록 추가하기
          </button>
        </div>

        <div className="space-y-4">
          {data.readingLogs.map(log => (
            <div key={log.id} className="p-4 bg-white border border-slate-100 rounded-xl shadow-sm relative group">
              <button 
                onClick={() => removeLog('reading', log.id)} 
                className="absolute top-4 right-4 text-slate-300 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"
              >
                <Trash2 size={16} />
              </button>
              <div className="flex items-start gap-3 mb-2">
                <div className="p-1.5 bg-emerald-50 rounded-lg">
                  <BookOpen className="w-4 h-4 text-emerald-600" />
                </div>
                <div>
                  <h4 className="font-bold text-slate-800">{log.bookTitle}</h4>
                  <p className="text-xs text-slate-500">{log.pages} 페이지 읽음</p>
                </div>
              </div>
              <p className="text-sm text-slate-600 italic bg-slate-50 p-3 rounded-lg border-l-4 border-emerald-400">
                "{log.highlight}"
              </p>
            </div>
          ))}
          {data.readingLogs.length === 0 && <p className="text-center text-slate-400 text-sm py-4">오늘의 독서 기록이 없습니다.</p>}
        </div>
      </section>
    </div>
  );
};

export default JournalSection;

import React, { useMemo, useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  LineChart, Line, Legend 
} from 'recharts';
import { getAllData } from '../services/storage';
import { DailyData } from '../types';

type StatsRange = 'week' | 'month' | 'year';

const StatsSection: React.FC = () => {
  const [range, setRange] = useState<StatsRange>('week');
  const allData = useMemo(() => getAllData(), []);

  const statsData = useMemo(() => {
    const sortedDates = Object.keys(allData).sort();
    const now = new Date();

    const filteredDates = sortedDates.filter(date => {
      const d = new Date(date);
      if (range === 'week') {
        const weekAgo = new Date();
        weekAgo.setDate(now.getDate() - 7);
        return d >= weekAgo;
      }
      if (range === 'month') {
        const monthAgo = new Date();
        monthAgo.setMonth(now.getMonth() - 1);
        return d >= monthAgo;
      }
      if (range === 'year') {
        const yearAgo = new Date();
        yearAgo.setFullYear(now.getFullYear() - 1);
        return d >= yearAgo;
      }
      return true;
    });

    return filteredDates.map(date => {
      const data = allData[date];
      const completedTasks = Object.values(data.checklist).filter(Boolean).length;
      const bibleChapters = data.bibleLogs.reduce((acc, log) => acc + log.chapterCount, 0);
      const readingPages = data.readingLogs.reduce((acc, log) => acc + log.pages, 0);

      return {
        name: date.slice(-5), // MM-DD
        '완료된 일과': completedTasks,
        '성경(장)': bibleChapters,
        '독서(쪽)': readingPages,
      };
    });
  }, [allData, range]);

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800">성장 통계</h2>
          <div className="flex bg-slate-100 p-1 rounded-lg">
            {(['week', 'month', 'year'] as StatsRange[]).map((r) => (
              <button
                key={r}
                onClick={() => setRange(r)}
                className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${
                  range === r 
                    ? 'bg-white text-emerald-600 shadow-sm' 
                    : 'text-slate-400'
                }`}
              >
                {r === 'week' ? '주간' : r === 'month' ? '월간' : '연간'}
              </button>
            ))}
          </div>
        </div>

        {statsData.length > 0 ? (
          <div className="space-y-8">
            <div className="h-64 w-full">
              <h3 className="text-sm font-bold text-slate-600 mb-4">일과 완료 추이</h3>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={statsData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} />
                  <YAxis hide />
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                  <Bar dataKey="완료된 일과" fill="#10b981" radius={[4, 4, 0, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div className="h-64 w-full">
              <h3 className="text-sm font-bold text-slate-600 mb-4">성경 및 독서량</h3>
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={statsData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} />
                  <YAxis hide />
                  <Tooltip 
                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  />
                  <Legend iconType="circle" wrapperStyle={{ fontSize: '10px' }} />
                  <Line type="monotone" dataKey="성경(장)" stroke="#8b5cf6" strokeWidth={2} dot={{ r: 4 }} />
                  <Line type="monotone" dataKey="독서(쪽)" stroke="#10b981" strokeWidth={2} dot={{ r: 4 }} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </div>
        ) : (
          <div className="h-64 flex items-center justify-center border-2 border-dashed border-slate-100 rounded-xl">
            <p className="text-slate-400 text-sm">데이터가 충분하지 않습니다.</p>
          </div>
        )}
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-emerald-50 p-6 rounded-2xl border border-emerald-100">
          <p className="text-emerald-600 text-xs font-bold mb-1">전체 누적 독서</p>
          <p className="text-2xl font-black text-emerald-900">
            {Object.values(allData).reduce((acc, d) => acc + d.readingLogs.reduce((p, l) => p + l.pages, 0), 0)}
            <span className="text-sm font-normal ml-1">쪽</span>
          </p>
        </div>
        <div className="bg-purple-50 p-6 rounded-2xl border border-purple-100">
          <p className="text-purple-600 text-xs font-bold mb-1">전체 누적 성경</p>
          <p className="text-2xl font-black text-purple-900">
            {Object.values(allData).reduce((acc, d) => acc + d.bibleLogs.reduce((p, l) => p + l.chapterCount, 0), 0)}
            <span className="text-sm font-normal ml-1">장</span>
          </p>
        </div>
      </div>
    </div>
  );
};

export default StatsSection;

import React, { useState, useEffect } from 'react';
import { ViewType, DailyData } from './types';
import { getDailyData, saveDailyData } from './services/storage';
import Navigation from './components/Navigation';
import DailyChecklist from './components/DailyChecklist';
import JournalSection from './components/JournalSection';
import VideoSection from './components/VideoSection';
import StatsSection from './components/StatsSection';
import { Calendar, ChevronLeft, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('today');
  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [dailyData, setDailyData] = useState<DailyData>(getDailyData(selectedDate));

  useEffect(() => {
    setDailyData(getDailyData(selectedDate));
  }, [selectedDate]);

  const handleUpdate = (newData: DailyData) => {
    setDailyData(newData);
    saveDailyData(newData);
  };

  const changeDate = (days: number) => {
    const d = new Date(selectedDate);
    d.setDate(d.getDate() + days);
    setSelectedDate(d.toISOString().split('T')[0]);
  };

  const formattedDate = new Intl.DateTimeFormat('ko-KR', { 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric', 
    weekday: 'long' 
  }).format(new Date(selectedDate));

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      {/* Header */}
      <header className="sticky top-0 bg-white/80 backdrop-blur-md border-b border-slate-100 z-40 px-6 py-4">
        <div className="max-w-4xl mx-auto flex items-center justify-between">
          <h1 className="text-2xl font-black text-emerald-600">뉴 라이프</h1>
          <div className="flex items-center gap-3 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-200">
            <Calendar size={16} className="text-slate-500" />
            <span className="text-xs font-bold text-slate-700">{formattedDate}</span>
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="max-w-4xl mx-auto px-6 pt-6">
        {/* Date Selector for Daily Views */}
        {(currentView === 'today' || currentView === 'journals') && (
          <div className="flex items-center justify-center gap-6 mb-8">
            <button 
              onClick={() => changeDate(-1)}
              className="p-2 hover:bg-white rounded-full transition-colors text-slate-400"
            >
              <ChevronLeft />
            </button>
            <span className="text-sm font-bold text-slate-500">{selectedDate === new Date().toISOString().split('T')[0] ? '오늘' : selectedDate}</span>
            <button 
              onClick={() => changeDate(1)}
              className="p-2 hover:bg-white rounded-full transition-colors text-slate-400"
            >
              <ChevronRight />
            </button>
          </div>
