import React, { useMemo, useState, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  LineChart, Line, Legend 
} from 'recharts';
import { getAllData } from '../services/storage';
import { DailyData } from '../types';

type StatsRange = 'week' | 'month' | 'year';

const StatsSection: React.FC = () => {
  const [range, setRange] = useState<StatsRange>('week');
  // 컴포넌트 마운트 시 최신 데이터를 로컬 상태로 관리
  const [allData, setAllData] = useState<Record<string, DailyData>>({});

  useEffect(() => {
    try {
      const data = getAllData();
      setAllData(data || {});
    } catch (error) {
      console.error("Failed to load data for stats:", error);
      setAllData({});
    }
  }, []);

  const statsData = useMemo(() => {
    const sortedDates = Object.keys(allData).sort();
    if (sortedDates.length === 0) return [];

    const now = new Date();

    const filteredDates = sortedDates.filter(date => {
      const d = new Date(date);
      if (isNaN(d.getTime())) return false; // 유효하지 않은 날짜 제외

      if (range === 'week') {
        const weekAgo = new Date();
        weekAgo.setDate(now.getDate() - 7);
        return d >= weekAgo;
      }
      if (range === 'month') {
        const monthAgo = new Date();
        monthAgo.setMonth(now.getMonth() - 1);
        return d >= monthAgo;
      }
      if (range === 'year') {
        const yearAgo = new Date();
        yearAgo.setFullYear(now.getFullYear() - 1);
        return d >= yearAgo;
      }
      return true;
    });

    return filteredDates.map(date => {
      const data = allData[date];
      // 데이터 누락 시 안전하게 처리 (Optional Chaining 및 Default values)
      const checklist = data?.checklist || {};
      const completedTasks = Object.values(checklist).filter(Boolean).length;
      const bibleChapters = (data?.bibleLogs || []).reduce((acc, log) => acc + (log.chapterCount || 0), 0);
      const readingPages = (data?.readingLogs || []).reduce((acc, log) => acc + (log.pages || 0), 0);

      return {
        name: date.slice(-5), // MM-DD
        '완료된 일과': completedTasks,
        '성경(장)': bibleChapters,
        '독서(쪽)': readingPages,
      };
    });
  }, [allData, range]);

  // 누적 통계 계산 (안전한 계산 방식)
  const cumulativeStats = useMemo(() => {
    const dataArray = Object.values(allData) as DailyData[];
    const totalReading = dataArray.reduce((acc, d) => 
      acc + (d.readingLogs || []).reduce((p, l) => p + (l.pages || 0), 0), 0);
    const totalBible = dataArray.reduce((acc, d) => 
      acc + (d.bibleLogs || []).reduce((p, l) => p + (l.chapterCount || 0), 0), 0);

    return { totalReading, totalBible };
  }, [allData]);

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-white rounded-[2rem] p-6 shadow-sm border border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-xl font-bold text-slate-800">성장 통계</h2>
          <div className="flex bg-slate-100 p-1 rounded-xl">
            {(['week', 'month', 'year'] as StatsRange[]).map((r) => (
              <button
                key={r}
                onClick={() => setRange(r)}
                className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${
                  range === r 
                    ? 'bg-white text-emerald-600 shadow-sm' 
                    : 'text-slate-400'
                }`}
              >
                {r === 'week' ? '주간' : r === 'month' ? '월간' : '연간'}
              </button>
            ))}
          </div>
        </div>

        {statsData.length > 0 ? (
          <div className="space-y-8">
            <div className="h-64 w-full">
              <h3 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2">
                <div className="w-1 h-3 bg-emerald-500 rounded-full"></div>
                일과 완료 추이
              </h3>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={statsData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                  <YAxis fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                  <Tooltip 
                    cursor={{ fill: '#f8fafc' }}
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', padding: '12px' }}
                  />
                  <Bar dataKey="완료된 일과" fill="#10b981" radius={[6, 6, 0, 0]} barSize={16} />
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div className="h-64 w-full border-t border-slate-50 pt-8">
              <h3 className="text-sm font-bold text-slate-600 mb-4 flex items-center gap-2">
                <div className="w-1 h-3 bg-purple-500 rounded-full"></div>
                성경 및 독서량
              </h3>
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={statsData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                  <YAxis fontSize={10} tickLine={false} axisLine={false} tick={{ fill: '#94a3b8' }} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', padding: '12px' }}
