const Login: React.FC<LoginProps> = ({ onLoginSuccess, onSignupClick, storedProfile }) => {
  const [userId, setUserId] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!storedProfile) {
      setError('등록된 회원이 없습니다. 회원가입을 진행해주세요.');
      return;
    }

    if (userId === storedProfile.userId && password === storedProfile.password) {
      onLoginSuccess();
    } else {
      setError('아이디 또는 비밀번호가 일치하지 않습니다.');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
      <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-xl p-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-emerald-100 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-inner">
            <Sparkles className="text-emerald-600 w-10 h-10" />
          </div>
          <h1 className="text-3xl font-black text-slate-800 mb-2">New Life</h1>
          <p className="text-slate-500 text-sm">평신도 신앙생활 가이드</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-6">
          <div className="space-y-4">
            <div className="relative">
              <User className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="text"
                placeholder="아이디"
                value={userId}
                onChange={(e) => setUserId(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl pl-12 pr-5 py-4 focus:ring-4 focus:ring-emerald-100 focus:border-emerald-400 outline-none transition-all font-semibold text-slate-700"
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="password"
                placeholder="비밀번호"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl pl-12 pr-5 py-4 focus:ring-4 focus:ring-emerald-100 focus:border-emerald-400 outline-none transition-all font-semibold text-slate-700"
              />
            </div>
          </div>

          {error && (
            <div className="p-3 rounded-xl bg-red-50 text-red-500 text-xs font-bold text-center">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold text-lg shadow-lg hover:bg-slate-800 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            로그인 <LogIn size={20} />
          </button>
        </form>

        <div className="mt-8 text-center">
          <p className="text-slate-400 text-sm">아직 계정이 없으신가요?</p>
          <button 
            onClick={onSignupClick}
            className="mt-2 text-emerald-600 font-bold hover:underline"
          >
            회원가입하기
          </button>
        </div>
      </div>

      <p className="mt-8 text-[10px] text-slate-400 text-center max-w-xs leading-relaxed">
        PC 버전을 이용하시려면 브라우저 설정에서<br/>
        '앱 설치' 또는 '홈 화면에 추가'를 선택하세요.
      </p>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { UserProfile, Gender, Region } from '../types';
import { ArrowLeft, Check, MapPin, User, Hash, Briefcase, Phone, Lock, Eye, EyeOff } from 'lucide-react';

interface SignupProps {
  onComplete: (profile: UserProfile) => void;
  onBack: () => void;
}

const Signup: React.FC<SignupProps> = ({ onComplete, onBack }) => {
  const [formData, setFormData] = useState<Partial<UserProfile>>({
    gender: 'male',
    region: '서울'
  });
  const [showPw, setShowPw] = useState(false);

  const regions: Region[] = ['서울', '경기', '인천', '강원', '충청', '전라', '경상', '제주', '해외'];

  const handleChange = (key: keyof UserProfile, value: string) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // 유효성 검사
    if (!formData.userId || !formData.password || !formData.name) {
      alert('필수 정보를 입력해주세요.');
      return;
    }

    const newProfile: UserProfile = {
      id: Math.random().toString(36).substr(2, 9),
      userId: formData.userId!,
      password: formData.password!,
      name: formData.name!,
      age: formData.age || '',
      affiliation: formData.affiliation || '',
      phoneNumber: formData.phoneNumber || '',
      gender: formData.gender as Gender,
      region: formData.region as Region,
      joinedAt: new Date().toISOString(),
    };
    onComplete(newProfile);
  };

  const InputField = ({ icon: Icon, label, type = "text", field, placeholder }: any) => (
    <div>
      <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">{label}</label>
      <div className="relative">
        <Icon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
        <input
          type={type}
          required
          value={formData[field as keyof UserProfile] || ''}
          onChange={(e) => handleChange(field as keyof UserProfile, e.target.value)}
          placeholder={placeholder}
          className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-10 pr-4 py-3 text-sm focus:ring-2 focus:ring-emerald-100 focus:border-emerald-400 outline-none transition-all font-semibold"
        />
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-white flex flex-col">
      <div className="sticky top-0 bg-white z-10 px-6 py-4 border-b border-slate-50 flex items-center gap-4">
        <button onClick={onBack} className="p-2 -ml-2 hover:bg-slate-50 rounded-full transition-colors">
          <ArrowLeft className="text-slate-800" />
        </button>
        <h2 className="text-lg font-bold text-slate-800">회원가입</h2>
      </div>

      <div className="flex-1 p-6 pb-10 max-w-lg mx-auto w-full">
        <form onSubmit={handleSubmit} className="space-y-6">
          {/* 계정 정보 섹션 */}
          <section className="space-y-4">
            <h3 className="text-sm font-bold text-emerald-600 mb-2">계정 정보</h3>
            <InputField icon={User} label="아이디" field="userId" placeholder="사용할 아이디 입력" />

            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">비밀번호</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input
                  type={showPw ? "text" : "password"}
                  required
                  value={formData.password || ''}
                  onChange={(e) => handleChange('password', e.target.value)}
                  placeholder="비밀번호 입력"
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-10 pr-10 py-3 text-sm focus:ring-2 focus:ring-emerald-100 focus:border-emerald-400 outline-none transition-all font-semibold"
                />
                <button 
                  type="button" 
                  onClick={() => setShowPw(!showPw)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 p-1"
                >
                  {showPw ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>
          </section>

          <hr className="border-slate-100" />

          {/* 개인 정보 섹션 */}
          <section className="space-y-4">
            <h3 className="text-sm font-bold text-emerald-600 mb-2">개인 정보</h3>
            <InputField icon={User} label="성명" field="name" placeholder="홍길동" />
            <div className="grid grid-cols-2 gap-4">
              <InputField icon={Hash} label="나이" field="age" placeholder="30" type="number" />
              <div>
                <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">성별</label>
                <div className="flex bg-slate-50 rounded-xl p-1 border border-slate-200">
                  {(['male', 'female'] as Gender[]).map((g) => (
                    <button
                      key={g}
                      type="button"
                      onClick={() => handleChange('gender', g)}
                      className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                        formData.gender === g 
                          ? 'bg-white text-emerald-600 shadow-sm' 
                          : 'text-slate-400'
                      }`}
                    >
                      {g === 'male' ? '남성' : '여성'}
                    </button>
                  ))}
                </div>
              </div>
            </div>
            <InputField icon={Briefcase} label="소속" field="affiliation" placeholder="○○교회 / 청년부" />
            <InputField icon={Phone} label="전화번호" field="phoneNumber" placeholder="010-0000-0000" type="tel" />

            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1.5 ml-1">지역</label>
              <div className="relative">
                <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <select
                  value={formData.region}
                  onChange={(e) => handleChange('region', e.target.value)}
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-10 pr-4 py-3 text-sm focus:ring-2 focus:ring-emerald-100 focus:border-emerald-400 outline-none transition-all font-semibold appearance-none"
                >
                  {regions.map((r) => (
                    <option key={r} value={r}>{r}</option>
                  ))}
                </select>
              </div>
            </div>
          </section>

          <button
            type="submit"
            className="w-full mt-8 bg-slate-900 text-white py-4 rounded-2xl font-bold text-lg shadow-lg hover:bg-slate-800 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            가입완료 <Check size={20} />
          </button>
        </form>
      </div>
    </div>
  );
};

export default Signup;

import React, { useState } from 'react';
import { UserProfile, Region, Gender } from '../types';
